const email = $json['Email'] || '';
const html = `
<!DOCTYPE html>
<html lang="pl">
<head><meta charset="UTF-8"><title>Błąd rejestracji</title>
<style>
  body{font-family:Arial,sans-serif;background:#f4f4f4;display:flex;align-items:center;justify-content:center;height:100vh;margin:0;}
  .card{background:#fff;border-radius:12px;padding:40px;max-width:480px;box-shadow:0 4px 20px rgba(0,0,0,.1);border-top:6px solid #e74c3c;}
  h1{color:#e74c3c;font-size:22px;}
  p{color:#333;line-height:1.5;}
</style></head>
<body>
  <div class="card">
    <h1>⚠️ Błąd rejestracji</h1>
    <p>Podany adres email <strong>${email}</strong> jest nieprawidłowy.</p>
    <p>Upewnij się, że adres zawiera znak "@" oraz kropkę (np. jan.kowalski@firma.pl) i spróbuj ponownie.</p>
  </div>
</body>
</html>`;
return [{ json: { ...$json, html_response: html } }];

const nip = ($input.first().json['NIP firmy (opcjonalnie)'] || '').toString().replace(/\D/g, '');
let nipValid = null;
let nipMessage = '';
if (nip.length > 0) {
  if (nip.length !== 10) {
    nipValid = false;
    nipMessage = 'NIP musi mieć dokładnie 10 cyfr';
  } else {
    const weights = [6, 5, 7, 2, 3, 4, 5, 6, 7];
    const digits = nip.split('').map(Number);
    const sum = weights.reduce((acc, w, i) => acc + w * digits[i], 0);
    const checksum = sum % 11;
    nipValid = checksum === digits[9];
    nipMessage = nipValid
      ? 'NIP poprawny (walidacja formatu, bez sprawdzenia w GUS)'
      : 'Nieprawidłowa suma kontrolna NIP';
  }
}
return [{
  json: {
    ...$input.first().json,
    nip_sformatowany: nip || null,
    nip_valid: nipValid,
    nip_message: nipMessage
  }
}];

const zarejestrowani = $json.zarejestrowani_uczestnicy;
const limit = $json.limit_miejsc;
const wolne_miejsca = limit - zarejestrowani - 1; // -1 bo dodajemy bieżące zgłoszenie
const procent_wypelnienia = Math.round(((zarejestrowani + 1) / limit) * 100);
return [{
  json: {
    ...$json,
    wolne_miejsca,
    procent_wypelnienia,
    ma_wolne_miejsca: wolne_miejsca >= 0
  }
}];

const imie = $json['Imię i nazwisko'] || '';
const id = $json.id_uczestnika || '';
const html = `
<!DOCTYPE html>
<html lang="pl">
<head><meta charset="UTF-8"><title>Lista rezerwowa</title>
<style>
  body{font-family:Arial,sans-serif;background:#fff8e1;display:flex;align-items:center;justify-content:center;min-height:100vh;margin:0;}
  .card{background:#fff;border-radius:12px;padding:40px;max-width:520px;box-shadow:0 4px 20px rgba(0,0,0,.1);border-top:6px solid #f39c12;}
  h1{color:#f39c12;}
  .id{background:#fef5e0;padding:8px 14px;border-radius:6px;font-family:monospace;display:inline-block;}
</style></head>
<body>
  <div class="card">
    <h1>📋 Zostałeś dodany do listy rezerwowej</h1>
    <p>Cześć ${imie}, wszystkie miejsca na wybrany termin są aktualnie zajęte.</p>
    <p>Twój numer zgłoszenia: <span class="id">${id}</span></p>
    <p>Skontaktujemy się z Tobą, jeśli zwolni się miejsce.</p>
  </div>
</body>
</html>`;
return [{ json: { ...$json, html_response: html } }];

