let pdf_base64 = null;
let pdf_available = false;
try {
  const bin = $input.first().binary;
  if (bin && bin.data && bin.data.data) {
    pdf_base64 = bin.data.data;
    pdf_available = true;
  }
} catch (e) {
  pdf_available = false;
}
const data = $('Code - Oblicz Statystyki (Agregacja)').item.json;
return [{ json: { ...data, pdf_base64, pdf_available } }];

const d = $json;
const nipInfo = d.nip_message ? `<p><strong>NIP:</strong> ${d.nip_sformatowany || '-'} — ${d.nip_message}</p>` : '';
const pdfLink = d.pdf_available
  ? `<a class="btn" href="data:application/pdf;base64,${d.pdf_base64}" download="potwierdzenie_${d.id_uczestnika}.pdf">⬇️ Pobierz potwierdzenie PDF</a>`
  : `<p style="color:#999;">Nie udało się wygenerować pliku PDF — potwierdzenie zostanie wysłane do Ciebie mailowo.</p>`;

const html = `
<!DOCTYPE html>
<html lang="pl">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1">
<title>Potwierdzenie rejestracji</title>
<style>
  body{font-family:'Segoe UI',Arial,sans-serif;background:#eef2f7;margin:0;padding:20px;display:flex;justify-content:center;}
  .card{background:#fff;border-radius:14px;padding:40px;max-width:560px;width:100%;box-shadow:0 6px 24px rgba(0,0,0,.08);border-top:6px solid #27ae60;}
  h1{color:#27ae60;font-size:24px;margin-top:0;}
  table{width:100%;border-collapse:collapse;margin:20px 0;}
  td{padding:8px 0;border-bottom:1px solid #eee;}
  td.label{color:#777;width:45%;}
  td.value{font-weight:600;color:#222;}
  .id-box{background:#eafaf1;color:#1e824c;font-family:monospace;font-size:15px;padding:10px 16px;border-radius:8px;display:inline-block;margin:10px 0;}
  .steps{background:#f8f9fb;border-radius:10px;padding:20px;margin-top:20px;}
  .steps h2{font-size:16px;margin-top:0;color:#333;}
  .steps li{margin-bottom:8px;color:#444;}
  .btn{display:inline-block;margin-top:16px;background:#27ae60;color:#fff;text-decoration:none;padding:10px 18px;border-radius:8px;font-weight:600;}
  @media (max-width:480px){.card{padding:24px;}}
</style>
</head>
<body>
  <div class="card">
    <h1>✅ Rejestracja zakończona sukcesem!</h1>
    <p>Dziękujemy, <strong>${d['Imię i nazwisko']}</strong>. Twoje zgłoszenie zostało przyjęte.</p>
    <div class="id-box">ID uczestnika: ${d.id_uczestnika}</div>
    <table>
      <tr><td class="label">Email</td><td class="value">${d['Email']}</td></tr>
      <tr><td class="label">Telefon</td><td class="value">${d.telefon_sformatowany}</td></tr>
      <tr><td class="label">Firma</td><td class="value">${d['Firma']}</td></tr>
      <tr><td class="label">Termin szkolenia</td><td class="value">${d['Termin szkolenia']}</td></tr>
      <tr><td class="label">Deadline płatności</td><td class="value">${d.deadline_platnosci}</td></tr>
      <tr><td class="label">Data rejestracji</td><td class="value">${d.timestamp_rejestracji}</td></tr>
    </table>
    ${nipInfo}
    <div class="steps">
      <h2>📌 Kolejne kroki</h2>
      <ol>
        <li>Opłać uczestnictwo w terminie do <strong>${d.deadline_platnosci}</strong>.</li>
        <li>Zachowaj swój numer ID uczestnika: <strong>${d.id_uczestnika}</strong>.</li>
        <li>Szczegóły dotyczące lokalizacji / linku otrzymasz mailem na 3 dni przed szkoleniem.</li>
      </ol>
      ${pdfLink}
    </div>
  </div>
</body>
</html>`;

return [{ json: { ...d, html_response: html } }];
